// Disable iOS WebView rubber-band bounce at scroll edges
try {
  if (window.Capacitor) {
    let _startY = 0;
    document.addEventListener('touchstart', function(e) { _startY = e.touches[0].pageY; }, { passive: true });
    document.addEventListener('touchmove', function(e) {
      // Find the nearest scrollable ancestor
      let el = e.target;
      while (el && el !== document.body && el !== document.documentElement) {
        const s = window.getComputedStyle(el);
        if (/(auto|scroll)/.test(s.overflowY) && el.scrollHeight > el.clientHeight) {
          const dy = e.touches[0].pageY - _startY;
          // At top scrolling up, or at bottom scrolling down → prevent bounce
          if ((el.scrollTop <= 0 && dy > 0) || (el.scrollTop + el.clientHeight >= el.scrollHeight && dy < 0)) {
            e.preventDefault();
          }
          return;
        }
        el = el.parentElement;
      }
      // Body-level scroll: check document scroll position
      const doc = document.scrollingElement || document.documentElement;
      const dy = e.touches[0].pageY - _startY;
      if ((doc.scrollTop <= 0 && dy > 0) || (doc.scrollTop + doc.clientHeight >= doc.scrollHeight && dy < 0)) {
        e.preventDefault();
      }
    }, { passive: false });
  }
} catch(e) {}

// roundRect polyfill for older Android WebViews
if (!CanvasRenderingContext2D.prototype.roundRect) {
  CanvasRenderingContext2D.prototype.roundRect = function(x,y,w,h,r) {
    if(typeof r==="number") r=[r,r,r,r]; if(!Array.isArray(r)) r=[0,0,0,0];
    this.moveTo(x+r[0],y); this.lineTo(x+w-r[1],y); this.quadraticCurveTo(x+w,y,x+w,y+r[1]);
    this.lineTo(x+w,y+h-r[2]); this.quadraticCurveTo(x+w,y+h,x+w-r[2],y+h);
    this.lineTo(x+r[3],y+h); this.quadraticCurveTo(x,y+h,x,y+h-r[3]);
    this.lineTo(x,y+r[0]); this.quadraticCurveTo(x,y,x+r[0],y); this.closePath();
  };
}

// Fix iOS double-tap delay: tell browser not to wait for zoom gesture on interactive elements
(function(){
  const s = document.createElement("style");
  s.textContent = "html{overscroll-behavior:none!important;}body{overscroll-behavior:none!important;-webkit-overflow-scrolling:touch;overflow-x:hidden!important;}button,input,select,textarea,a,[role=button]{touch-action:manipulation;-webkit-tap-highlight-color:transparent;}";
  document.head.appendChild(s);
})();

