                  <button onClick={()=>{setLastWellbeingDate(todayStr());try{localStorage.setItem("wellbeing_date_v1",todayStr());}catch{}}}
                    style={{fontSize:11,color:C.lt,background:_bN,border:_bN,cursor:_cP}}>I'm okay, dismiss</button>
